  const repairGeneratedText = async (originalText, issue, targetLength, context, preserveCitations = false) => {
      debugLog(`Repairing text: ${issue} (Target: ~${targetLength} words)`);
      const citationRule = preserveCitations ? '\n                - CRITICAL: Preserve all citation markers in the format [⁽¹⁾](url). Keep them exactly as-is — do not remove, merge, or reformat them. They are important hyperlinks.' : '';

      // ── Citation extraction (pre-repair) ──
      const citationRegex = /\[⁽[⁰¹²³⁴⁵⁶⁷⁸⁹]+⁾\]\([^)]+\)/g;
      let extractedCitations = [];
      if (preserveCitations) {
          let m;
          while ((m = citationRegex.exec(originalText)) !== null) {
              // Grab the sentence surrounding this citation for context matching
              const beforeSlice = originalText.substring(Math.max(0, m.index - 120), m.index);
              const afterSlice = originalText.substring(m.index + m[0].length, Math.min(originalText.length, m.index + m[0].length + 60));
              // Extract keywords (4+ char words) from surrounding context
              const contextWords = (beforeSlice + ' ' + afterSlice)
                  .replace(/[^\w\s]/g, ' ')
                  .split(/\s+/)
                  .filter(w => w.length >= 4)
                  .map(w => w.toLowerCase());
              extractedCitations.push({ marker: m[0], contextWords, before: beforeSlice.trim() });
          }
          if (extractedCitations.length > 0) {
              debugLog(`[CitationRecovery] Extracted ${extractedCitations.length} citations before repair`);
          }
      }

      try {
          let prompt = "";
          if (issue === 'too_short') {
              prompt = `
                You are an expert educational editor. The text below is too short.
                Task: Expand the text to approximately ${targetLength} words.
                - Add relevant examples, analogies, and descriptive details to enhance understanding.
                - Clarify complex points.
                - Maintain the reading level and tone appropriate for: ${context}.
                - Do not change the core topic.${citationRule}
                Text to Expand:
                "${originalText}",
                Return ONLY the expanded text.
              `;
          } else if (issue === 'too_long') {
              prompt = `
                You are an expert educational editor. The text below is too long.
                Task: Condense the text to approximately ${targetLength} words.
                - Remove conversational filler, redundancy, and fluff.
                - Preserve all key concepts, definitions, and facts.
                - Maintain the reading level appropriate for: ${context}.${citationRule}
                Text to Condense:
                "${originalText}",
                Return ONLY the condensed text.
              `;
          } else {
              return originalText;
          }
          let result = await callOllama(prompt);
          if (!result) return originalText;

          // ── Citation recovery (post-repair) ──
          if (preserveCitations && extractedCitations.length > 0) {
              const survivedCount = extractedCitations.filter(c => result.includes(c.marker)).length;
              const lostCitations = extractedCitations.filter(c => !result.includes(c.marker));
              debugLog(`[CitationRecovery] ${survivedCount}/${extractedCitations.length} citations survived repair, ${lostCitations.length} lost`);

              if (lostCitations.length > 0) {
                  // Split result into sentences for matching
                  const sentences = (result.match(/[^.!?]*[.!?]+[\s]*/g) || [result]).map(s => s.trim()).filter(Boolean);
                  for (const lost of lostCitations) {
                      // Score each sentence by keyword overlap with the original context
                      let bestIdx = -1;
                      let bestScore = 0;
                      sentences.forEach((sentence, idx) => {
                          const sentenceWords = sentence.toLowerCase().replace(/[^\w\s]/g, ' ').split(/\s+/);
                          const overlap = lost.contextWords.filter(w => sentenceWords.includes(w)).length;
                          if (overlap > bestScore) {
                              bestScore = overlap;
                              bestIdx = idx;
                          }
                      });
                      // Require at least 2 keyword matches to avoid false placement
                      if (bestIdx >= 0 && bestScore >= 2) {
                          // Insert citation at end of the best-matching sentence (before final punctuation)
                          const sentence = sentences[bestIdx];
                          const punctMatch = sentence.match(/([.!?])\s*$/);
                          if (punctMatch) {
                              sentences[bestIdx] = sentence.replace(/([.!?])\s*$/, ` ${lost.marker}$1`);
                          } else {
                              sentences[bestIdx] = sentence + ' ' + lost.marker;
                          }
                          debugLog(`[CitationRecovery] Re-inserted ${lost.marker} at sentence ${bestIdx} (score: ${bestScore})`);
                      } else {
                          warnLog(`[CitationRecovery] Could not find match for ${lost.marker} (best score: ${bestScore})`);
                      }
                  }
                  result = sentences.join(' ');
              }
          }

          return result;
      } catch (e) {
          warnLog("Text Repair Failed:", e);
          return originalText;
      }
  };
  const applyGlobalCitations = (text, supports, localToGlobalMap) => {
    if (!supports || !localToGlobalMap) return text;
    let insertions = [];
    supports.forEach(support => {
        const chunkIndices = support.groundingChunkIndices;
        if (!chunkIndices || chunkIndices.length === 0) return;
        let idx = support.segment?.endIndex;
        if (idx === undefined) return;
        const globalIds = chunkIndices
            .map(localId => localToGlobalMap.get(localId))
            .filter(id => id !== undefined)
            .sort((a, b) => a - b);
        if (globalIds.length > 0) {
            const label = " " + globalIds.map(id => `[${id}]`).join(', ');
            insertions.push({ idx, label });
        }
    });
    insertions.sort((a, b) => b.idx - a.idx);
    let newText = text;
    insertions.forEach(({ idx, label }) => {
        if (idx <= newText.length) {
            newText = newText.slice(0, idx) + label + newText.slice(idx);
        }
    });
    newText = newText.replace(/(\s*\[[\d,\s\[\]]+\])([.!?])/g, '$2$1');
    return newText;
  };
  const performDeepVerification = async (fullText) => {
      const chunks = chunkText(fullText, 6000);
      let combinedVerificationText = "";
      const globalSources = [];
      const sourceUrlToIndexMap = new Map();
      for (let i = 0; i < chunks.length; i++) {
          setGenerationStep(`Step 1/2: Verifying segment ${i + 1} of ${chunks.length}...`);
          const verificationPrompt = `
              Verify the factual accuracy of the following text segment (${i + 1}/${chunks.length}) using Google Search.
              Text Segment:
              "${chunks[i]}",
              Task:
              1. Identify specific factual claims (dates, names, statistics).
              2. Cross-reference them with reliable sources via Google Search.
              3. ONLY if you find actual errors, myths, or outdated information, include a "**Discrepancies**" section listing each specific error with the correction.
              4. List key "**Verified Facts**" - the confirmed accurate facts from the text.
              IMPORTANT RULES:
              - Do NOT include a Discrepancies section if no genuine errors were found.
              - Do NOT write "No discrepancies found" or similar - simply omit the section entirely.
              - Only count something as a discrepancy if it is factually incorrect, not just incomplete.
              - Focus on the Verified Facts section when the content is accurate.
              Return a concise summary of findings for this segment.
          `;
          try {
              const result = await callOllama(verificationPrompt, false, true, null, sourceTopic || null);
              if (result) {
                  let chunkRawText = "";
                  let metadata = null;
                  if (typeof result === 'object' && result !== null) {
                      chunkRawText = result.text || "";
                      metadata = result.groundingMetadata;
                  } else {
                      chunkRawText = String(result || "");
                  }
                  let chunkTextWithGlobalCitations = chunkRawText;
                  if (metadata && metadata.groundingChunks) {
                      const localToGlobalIndexMap = new Map();
                      metadata.groundingChunks.forEach((chunk, localIdx) => {
                          const uri = chunk.web?.uri;
                          const title = chunk.web?.title;
                          if (uri) {
                              let globalIndex;
                              if (sourceUrlToIndexMap.has(uri)) {
                                  globalIndex = sourceUrlToIndexMap.get(uri);
                              } else {
                                  globalSources.push({ uri, title });
                                  globalIndex = globalSources.length;
                                  sourceUrlToIndexMap.set(uri, globalIndex);
                              }
                              localToGlobalIndexMap.set(localIdx, globalIndex);
                          }
                      });
                      if (metadata.groundingSupports) {
                         chunkTextWithGlobalCitations = applyGlobalCitations(chunkRawText, metadata.groundingSupports, localToGlobalIndexMap);
                      }
                  }
                  if (chunkTextWithGlobalCitations.trim()) {
                      combinedVerificationText += `\n\n#### Segment ${i+1} Findings\n${chunkTextWithGlobalCitations}`;
                  }
              }
          } catch (err) {
               warnLog(`Verification failed for chunk ${i}`, err);
          }
          if (i < chunks.length - 1) await new Promise(r => setTimeout(r, 800));
      }
      return {
          text: combinedVerificationText,
          sources: globalSources
      };
  };
    const ensureTitleHeading = (text) => {
        if (!text) return text;
        const lines = text.split('\n');
        const firstNonEmptyIdx = lines.findIndex(l => l.trim().length > 0);
        if (firstNonEmptyIdx === -1) return text;
        const firstLine = lines[firstNonEmptyIdx].trim();
        // Skip if already a markdown heading
        if (/^#{1,6}\s/.test(firstLine)) return text;
        // Skip if line is too long to be a title (likely a body paragraph)
        if (firstLine.length > 120) return text;
        // Skip if there aren't at least 2 non-empty lines (need title + content)
        const nonEmptyCount = lines.filter(l => l.trim().length > 0).length;
        if (nonEmptyCount < 2) return text;
        // Handle "Title: XYZ" format from multi-chunk pipeline
        const titlePrefixMatch = firstLine.match(/^Title:\s*(.+)/i);
        if (titlePrefixMatch) {
            lines[firstNonEmptyIdx] = `# ${titlePrefixMatch[1]}`;
        } else {
            // Plain title line — add # prefix
            lines[firstNonEmptyIdx] = `# ${firstLine}`;
        }
        return lines.join('\n');
    };
    const cleanSourceMetaCommentary = (text) => {
        if (!text) return text;
        let cleaned = text;
        cleaned = cleaned.replace(/\n*\s*\*\((?:Word Count|Note|Target|Revised|Total)[^)]{5,}\)\*\s*\n*/gi, '\n');
        const revisedMatch = cleaned.match(/^(###?\s*Revised\s+(?:Content|Version)[^\n]*\n)/mi);
        if (revisedMatch) {
            const revisedIdx = cleaned.indexOf(revisedMatch[0]);
            if (revisedIdx > 0) {
                cleaned = cleaned.substring(revisedIdx + revisedMatch[0].length);
            }
        }
        cleaned = cleaned.replace(/^(?:Note that |The research confirms |I (?:will|must|should) (?:now )?(?:write|increase|revise|ensure)|This (?:is|meets|exceeds) (?:within|significantly|the target)|Aiming for \d+ words)[^\n]*\n*/gmi, '');
        cleaned = cleaned.replace(/\n---\n\s*\n/g, '\n\n');
        cleaned = cleaned.replace(/([^\n])\n(#{1,4}\s)/g, '$1\n\n$2');
        cleaned = cleaned.replace(/(#{1,4}\s[^\n]+)\n([^#\n])/g, '$1\n\n$2');
        const lines = cleaned.split('\n');
        const nonEmptyLines = lines.filter(l => l.trim().length > 0);
        const headerLines = nonEmptyLines.filter(l => /^#{1,4}\s/.test(l.trim()));
        const headerRatio = nonEmptyLines.length > 3 ? headerLines.length / nonEmptyLines.length : 0;
        if (headerRatio > 0.4) {
            warnLog(`[SourceCleanup] Header-heavy text detected: ${headerLines.length}/${nonEmptyLines.length} lines (${(headerRatio * 100).toFixed(0)}%). Normalizing...`);
            let prevWasHeader = false;
            cleaned = lines.map((line, idx) => {
                const trimmed = line.trim();
                const headerMatch = trimmed.match(/^(#{1,4})\s+(.*)/);
                if (!headerMatch) {
                    prevWasHeader = false;
                    return line;
                }
                const headerText = headerMatch[2];
                const headerLevel = headerMatch[1].length;
                if (idx === lines.findIndex(l => l.trim().length > 0)) {
                    prevWasHeader = true;
                    return line;
                }
                const isLongLine = headerText.length > 120;
                const isConsecutive = prevWasHeader;
                if (!isLongLine && !isConsecutive && headerLevel <= 3 && headerText.length < 80) {
                    prevWasHeader = true;
                    return line;
                }
                prevWasHeader = false;
                return headerText;
            }).join('\n');
        } else {
            cleaned = cleaned.replace(/^(#{1,4})\s+(.{150,})$/gm, (match, hashes, text) => {
                warnLog(`[SourceCleanup] Stripping long header (${text.length} chars)`);
                return text;
            });
        }
        cleaned = cleaned.replace(/\n{4,}/g, '\n\n\n');
        return cleaned.trim();
    };
